#include "controller.h"

static void controller_apply_state(controller_t *controller, bool heater_on, controller_state_t state)
{
    if (controller == 0) {
        return;
    }

    controller->heater_on = heater_on;
    controller->state = state;
}

static void controller_set_safe_off(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller->safe_heater_on = false;
    controller_apply_state(controller, false, CONTROLLER_STATE_SAFE_OFF);
}

static void controller_set_heating(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller->safe_heater_on = true;
    controller_apply_state(controller, true, CONTROLLER_STATE_HEATING);
}

static void controller_set_holding(controller_t *controller, bool heater_on)
{
    controller_apply_state(controller, heater_on, CONTROLLER_STATE_HOLDING);
}

static bool controller_sensor_is_stale(const controller_t *controller, uint32_t now_ms)
{
    if ((controller == 0) || !controller->has_valid_sensor) {
        return false;
    }

    return (now_ms - controller->last_valid_sensor_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE: {
        const bool had_previous_valid_sample = controller->has_valid_sensor;
        const int previous_temperature_c = controller->last_temperature_c;
        const bool rising = had_previous_valid_sample && (input.temperature_c > previous_temperature_c);

        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            controller_set_heating(controller);
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            controller_set_safe_off(controller);
        } else if ((input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) && rising) {
            controller_set_holding(controller, false);
        } else {
            controller_set_holding(controller, controller->safe_heater_on);
        }
        break;
    }
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        output.timed_out = true;
        break;
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        if (controller_sensor_is_stale(controller, input.now_ms)) {
            controller->has_valid_sensor = false;
            controller_set_safe_off(controller);
            output.timed_out = true;
        }
        break;
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

